import React, { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api";
import StatCard from "../../components/common/StatCard.js";
import CaseRow from "../../components/cases/CaseRow.js";
import { Plus, FolderOpen, Bell, Search, X, Check, ClipboardList } from "lucide-react";
import "./Dashboard.css";

export default function LegalLensDashboard() {
  const user = JSON.parse(localStorage.getItem("user"));
  const navigate = useNavigate();

  const [message, setMessage] = useState("");
  const [assignedCases, setAssignedCases] = useState([]);
  const [recentCases, setRecentCases] = useState([]);
  const [caseStats, setCaseStats] = useState({
    totalAssigned: 0, activeCases: 0, closedCases: 0, highPriorityCases: 0,
  });
  const [notifications, setNotifications] = useState([]);
  const [showNotifPanel, setShowNotifPanel] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);

  // Audit log preview for Lead Investigator (role_id 2)
  const [auditPreview, setAuditPreview] = useState([]);

  const notifRef = useRef(null);

  const isAdmin = user?.role_id === 1;
  const isLead = user?.role_id === 2;

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const [dashRes, casesRes, recentRes, statsRes, notifRes] = await Promise.all([
          api.get("/dashboard"),
          api.get("/assigned-cases"),
          api.get("/recent-cases"),
          api.get("/case-stats"),
          api.get("/notifications"),
        ]);

        setMessage(dashRes.data.message || "");
        setAssignedCases(casesRes.data.message === "no assigned cases" ? [] : casesRes.data);
        setRecentCases(recentRes.data.message === "no recent cases" ? [] : recentRes.data);
        setCaseStats(statsRes.data);
        setNotifications(Array.isArray(notifRes.data) ? notifRes.data : []);
        setUnreadCount((notifRes.data || []).filter((n) => !n.read).length);

        // Fetch audit log preview for Lead Investigator
        if (user?.role_id === 2) {
          const auditRes = await api.get("/audit-logs?page=1&limit=5");
          setAuditPreview(auditRes.data.logs || []);
        }
      } catch (err) {
        console.error("Dashboard fetch error:", err);
        // Only redirect on auth errors
        if (err.response?.status === 401 || err.response?.status === 403) {
          localStorage.removeItem("token");
          localStorage.removeItem("user");
          navigate("/", { replace: true });
        }
      }
    };
    fetchAll();
  }, [navigate, user?.role_id]);

  // Close notification panel when clicking outside
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (notifRef.current && !notifRef.current.contains(e.target)) {
        setShowNotifPanel(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleMarkRead = async (id) => {
    try {
      await api.patch(`/notifications/${id}/read`);
      setNotifications((prev) => prev.map((n) => (n._id === id ? { ...n, read: true } : n)));
      setUnreadCount((c) => Math.max(0, c - 1));
    } catch { /* silent */ }
  };

  const handleMarkAllRead = async () => {
    try {
      await api.patch("/notifications/read-all");
      setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
      setUnreadCount(0);
    } catch { /* silent */ }
  };

  const getPriorityLabel = (num) => {
    switch (num) {
      case 3: return "High";
      case 2: return "Medium";
      case 1: return "Low";
      default: return "Unknown";
    }
  };

  const formatTime = (ts) => {
    const diff = Date.now() - new Date(ts).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return "Just now";
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    return `${Math.floor(hrs / 24)}d ago`;
  };

  const ACTION_COLORS = {
    created: "#60a5fa", assigned: "#a78bfa", uploaded: "#34d399",
    verified: "#fbbf24", deleted: "#f87171", updated: "#fb923c",
    removed: "#f87171", added: "#a78bfa",
  };

  const getActionColor = (action = "") => {
    const lower = action.toLowerCase();
    for (const [key, color] of Object.entries(ACTION_COLORS)) {
      if (lower.includes(key)) return color;
    }
    return "#94a3b8";
  };

  return (
    <div className="dashboardMain">
      {/* TOP HEADER */}
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText">
            <span>LEGALLENS</span> Dashboard
          </h1>
          <p className="systemStatus">
            Welcome back,{" "}
            <span className="highlightText">{user?.name || "User"}</span>
            {message ? ` • ${message}` : ""}
          </p>
        </div>

        <div className="headerActions">
          <div className="searchContainer">
            <Search className="searchIcon" size={16} />
            <input
              type="text"
              placeholder="Search cases..."
              className="searchInput"
              onKeyDown={(e) => {
                if (e.key === "Enter" && e.target.value.trim()) {
                  navigate("/cases");
                }
              }}
            />
          </div>

          {/* Notification Bell with dropdown */}
          <div ref={notifRef} style={{ position: "relative" }}>
            <button
              className="notificationBtn"
              onClick={() => setShowNotifPanel((v) => !v)}
              title="Notifications"
            >
              <Bell size={20} />
              {unreadCount > 0 && (
                <span className="badge notifBadgeRed">
                  {unreadCount > 9 ? "9+" : unreadCount}
                </span>
              )}
            </button>

            {showNotifPanel && (
              <div className="notifDropdown">
                <div className="notifDropdownHeader">
                  <span>Notifications</span>
                  {unreadCount > 0 && (
                    <button className="markAllReadBtn" onClick={handleMarkAllRead}>
                      <Check size={12} /> Mark all read
                    </button>
                  )}
                </div>
                <div className="notifDropdownList">
                  {notifications.length === 0 ? (
                    <p className="noNotifsMsg">No notifications</p>
                  ) : (
                    notifications.slice(0, 15).map((n) => (
                      <div
                        key={n._id}
                        className={`notifDropItem ${n.read ? "notifRead" : "notifUnread"}`}
                      >
                        <div
                          className="notifDotIndicator"
                          style={{ background: n.read ? "#22c55e" : "#ef4444" }}
                        />
                        <div className="notifDropContent">
                          <p className="notifDropText">{n.message}</p>
                          <span className="notifDropTime">{formatTime(n.created_at)}</span>
                        </div>
                        {!n.read && (
                          <button
                            className="notifReadBtn"
                            onClick={() => handleMarkRead(n._id)}
                            title="Mark as read"
                          >
                            <Check size={12} />
                          </button>
                        )}
                      </div>
                    ))
                  )}
                </div>
                <div className="notifDropdownFooter">
                  <button
                    onClick={() => {
                      navigate("/notifications");
                      setShowNotifPanel(false);
                    }}
                  >
                    View all notifications →
                  </button>
                </div>
              </div>
            )}
          </div>

          {/* Avatar */}
          <div
            className="userAvatar"
            onClick={() => navigate("/profile")}
            title="View Profile"
          >
            {user?.avatar ? (
              <img
                src={`http://localhost:5000${user.avatar}`}
                alt="avatar"
                style={{ width: "100%", height: "100%", borderRadius: "9999px", objectFit: "cover" }}
              />
            ) : (
              <span style={{ color: "white", fontWeight: 700, fontSize: "0.875rem", display: "flex", alignItems: "center", justifyContent: "center", height: "100%" }}>
                {user?.name?.charAt(0)?.toUpperCase()}
              </span>
            )}
          </div>
        </div>
      </header>

      {/* STATS GRID */}
      <div className="statsGrid">
        <StatCard title="Total Cases" value={caseStats.totalAssigned} type="total" />
        <StatCard title="Active Cases" value={caseStats.activeCases} type="active" />
        <StatCard title="Closed Cases" value={caseStats.closedCases} type="closed" />
        <StatCard title="High Priority" value={caseStats.highPriorityCases} type="priority" />
      </div>

      {/* MIDDLE SECTION */}
      <div className="middleSection">
        <section className="glassCard">
          <div className="sectionHeader">
            <h2>Recent Cases</h2>
            <button className="viewAllBtn" onClick={() => navigate("/cases")}>
              View All ›
            </button>
          </div>
          <div className="caseList">
            {recentCases.length === 0 ? (
              <p className="noCasesMsg">No recent open cases</p>
            ) : (
              recentCases.map((c) => (
                <CaseRow
                  key={c.id}
                  id={c.caseId}
                  title={c.title}
                  priority={getPriorityLabel(c.priority)}
                  status={c.status}
                />
              ))
            )}
          </div>
        </section>

        {/* My Assigned Cases — non-admin users */}
        {!isAdmin && (
          <section className="glassCard">
            <div className="sectionHeader">
              <h2>My Assigned Cases</h2>
              <button className="viewAllBtn" onClick={() => navigate("/cases")}>
                View All ›
              </button>
            </div>
            <div className="caseList">
              {assignedCases.length === 0 ? (
                <p className="noCasesMsg">No cases assigned yet</p>
              ) : (
                assignedCases.map((c) => (
                  <CaseRow
                    key={c.id}
                    id={c.caseId}
                    title={c.title}
                    priority={getPriorityLabel(c.priority)}
                    status={c.status}
                  />
                ))
              )}
            </div>
          </section>
        )}
      </div>

      {/* BOTTOM SECTION */}
      <div className="bottomSection">
        {/* Recent Notifications */}
        <section className="glassCard">
          <div className="sectionHeader">
            <h2 className="sectionTitle">Recent Notifications</h2>
            <button className="viewAllBtn" onClick={() => navigate("/notifications")}>
              View All ›
            </button>
          </div>
          <div className="notificationList">
            {notifications.length === 0 ? (
              <p className="noCasesMsg">No notifications</p>
            ) : (
              notifications.slice(0, 5).map((n) => (
                <div
                  key={n._id}
                  className={`notifItem ${n.read ? "" : "notifItemUnread"}`}
                >
                  <div style={{ display: "flex", alignItems: "flex-start", gap: "0.75rem" }}>
                    <div
                      style={{
                        width: 8, height: 8, borderRadius: "50%",
                        background: n.read ? "#22c55e" : "#ef4444",
                        marginTop: 5, flexShrink: 0,
                      }}
                    />
                    <div>
                      <p className="notifText">{n.message}</p>
                      <span className="notifTime">{formatTime(n.created_at)}</span>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </section>

        {/* Admin: Quick Actions */}
        {isAdmin && (
          <section className="glassCard">
            <h2 className="sectionTitle">Quick Actions</h2>
            <div className="actionsGrid">
              <button
                className="primaryActionBtn"
                onClick={() => navigate("/create-case")}
              >
                <Plus size={18} /> Create New Case
              </button>
              <button
                className="secondaryActionBtn"
                onClick={() => navigate("/add-members")}
              >
                <FolderOpen size={18} /> Manage Members
              </button>
              <button
                className="secondaryActionBtn"
                onClick={() => navigate("/audit-log")}
              >
                <ClipboardList size={18} /> View Audit Log
              </button>
            </div>
          </section>
        )}

        {/* Lead Investigator: Audit Log Preview */}
        {isLead && (
          <section className="glassCard">
            <div className="sectionHeader">
              <h2 className="sectionTitle">
                <ClipboardList size={16} style={{ marginRight: 6, verticalAlign: "middle" }} />
                My Cases — Recent Activity
              </h2>
              <button
                className="viewAllBtn"
                onClick={() => navigate("/audit-log")}
              >
                View Full Log ›
              </button>
            </div>
            <div style={{ padding: "0.25rem 0" }}>
              {auditPreview.length === 0 ? (
                <p className="noCasesMsg">No audit activity for your cases yet</p>
              ) : (
                auditPreview.map((log) => (
                  <div
                    key={log._id}
                    style={{
                      display: "flex",
                      alignItems: "flex-start",
                      gap: "0.75rem",
                      padding: "0.6rem 0",
                      borderBottom: "1px solid rgba(255,255,255,0.04)",
                    }}
                  >
                    <div
                      style={{
                        width: 8,
                        height: 8,
                        borderRadius: "50%",
                        background: getActionColor(log.action),
                        marginTop: 5,
                        flexShrink: 0,
                      }}
                    />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <p
                        style={{
                          margin: 0,
                          fontSize: "0.82rem",
                          color: "#94a3b8",
                          whiteSpace: "nowrap",
                          overflow: "hidden",
                          textOverflow: "ellipsis",
                        }}
                      >
                        {log.action}
                      </p>
                      <span style={{ fontSize: "0.72rem", color: "#334155" }}>
                        {log.user?.name} •{" "}
                        {new Date(log.timestamp).toLocaleDateString("en-GB", {
                          day: "2-digit", month: "short", year: "numeric",
                        })}
                      </span>
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>
        )}
      </div>
    </div>
  );
}
